/**
 * Individual Profile Settings Page
 * 
 * Manages individual user profile information and preferences including
 * personal details, contact information, language, theme, and notification
 * settings. Tracks form changes and handles profile updates.
 */

import React, { useEffect, useState } from 'react';
import { useTranslation } from 'react-i18next';
import { z } from 'zod';
import { useToast } from '@/app/providers/ToastContext.jsx';
import { useTheme } from '@/app/providers/ThemeContext.jsx';
import { useLanguage } from '@/app/providers/LanguageContext.jsx';
import { ProfileUtils } from '@/features/settings/utils/profile-utils.js';
import { countries } from '@/shared/utils/constants/countries-with-flags.js';
import { ghanaRegions } from '@/shared/utils/constants/ghana-regions.js';
import { createIndividualSettingsSchema } from '@/shared/utils/validation/settingsSchemas.js';
import { mapFieldErrors, trimAndRequire } from '@/shared/utils/validation/helpers.js';
import { useMutation, useQuery } from '@/shared/hooks';
import { queryKeys } from '@/shared/utils/queryKeys.js';
import { profileService } from '@/features/settings/services';
import CustomSelect from '@/shared/components/CustomSelect.jsx';

const Profile = () => {
  const { t } = useTranslation();
  const { success, error: showError } = useToast();
  const { theme, updateTheme } = useTheme();
  const { changeLanguage, currentLanguage } = useLanguage();

  const [formData, setFormData] = useState(ProfileUtils.getInitialFormData());
  const [originalFormData, setOriginalFormData] = useState(ProfileUtils.getInitialFormData());
  const [isEditMode, setIsEditMode] = useState(false);
  const [isEditModePreferences, setIsEditModePreferences] = useState(false);
  const [formErrors, setFormErrors] = useState({});
  const [formErrorsPreferences, setFormErrorsPreferences] = useState({});
  const [windowWidth, setWindowWidth] = useState(typeof window !== 'undefined' ? window.innerWidth : 1024);

  // Use React Query to fetch profile data with caching
  const { data: profileData, isLoading: isFetchingProfile } = useQuery({
    queryKey: queryKeys.settings.profile(),
    queryFn: () => profileService.getUserProfile(),
    staleTime: 5 * 60 * 1000, // 5 minutes
    cacheTime: 10 * 60 * 1000, // 10 minutes
    refetchOnWindowFocus: false,
  });

  const isMobile = windowWidth <= 768;
  const isTablet = windowWidth > 768 && windowWidth <= 1024;

  // Use React Query mutations for profile updates with automatic cache invalidation
  const updateProfileMutation = useMutation({
    mutationFn: async (updateData) => {
      return await profileService.updateProfile(updateData);
    },
    invalidateQueries: [
      queryKeys.settings.profile(),
      queryKeys.settings.all(),
    ],
    onSuccess: () => {
      // Update localStorage
      const currentUserData = JSON.parse(localStorage.getItem('userData') || '{}');
      const preservedId = currentUserData.id;
      const updatedUserData = {
        ...currentUserData,
        id: preservedId,
        country: formData.country,
        city: formData.city,
        area: formData.area,
        digital_address: formData.digital_address,
        updated_at: new Date().toISOString()
      };
      localStorage.setItem('userData', JSON.stringify(updatedUserData));
    },
  });

  const updatePreferencesMutation = useMutation({
    mutationFn: async (preferences) => {
      return await profileService.updateUserPreferences(preferences);
    },
    invalidateQueries: [
      queryKeys.settings.profile(),
      queryKeys.settings.all(),
    ],
    onSuccess: () => {
      success(t('preferencesUpdated', { ns: 'settings', defaultValue: 'Preferences updated successfully!' }));
    },
    onError: (error) => {
      showError(t('pleaseTryAgain', { ns: 'settings', defaultValue: 'Please try again.' }));
    },
  });

  // Sync form data when profile data changes
  useEffect(() => {
    if (profileData && !isEditMode && !isEditModePreferences) {
      const mappedFormData = ProfileUtils.mapProfileDataToForm(profileData);
      if (mappedFormData) {
        // Sync theme from ThemeContext (source of truth)
        const syncedFormData = {
          ...mappedFormData,
          theme: theme || mappedFormData.theme || 'Light',
        };
        setFormData(syncedFormData);
        setOriginalFormData(syncedFormData);
      }
    }
  }, [profileData, theme, isEditMode, isEditModePreferences]);

  // Handle window resize for responsive design
  useEffect(() => {
    let resizeTimer = null;
    const handleResize = () => {
      // Debounce resize events to prevent excessive re-renders
      if (resizeTimer) {
        clearTimeout(resizeTimer);
      }
      resizeTimer = setTimeout(() => {
        setWindowWidth(window.innerWidth);
      }, 100);
    };

    window.addEventListener('resize', handleResize);
    return () => {
      window.removeEventListener('resize', handleResize);
      if (resizeTimer) {
        clearTimeout(resizeTimer);
      }
    };
  }, []);

  const handleEditClick = () => {
    setIsEditMode(true);
  };

  const handleEditClickPreferences = () => {
    setIsEditModePreferences(true);
  };

  const handleCancelClick = () => {
    setFormData(originalFormData); // Revert to original data
    setFormErrors({});
    setIsEditMode(false);
  };

  const handleCancelClickPreferences = () => {
    setFormData(originalFormData); // Revert to original data
    setFormErrorsPreferences({});
    setIsEditModePreferences(false);
  };

  const clearFieldError = (name) => {
    if (formErrors[name]) {
      setFormErrors((prev) => {
        const next = { ...prev };
        delete next[name];
        if (Object.keys(next).length === 1 && next._form) {
          delete next._form;
        }
        return next;
      });
    }
  };

  const clearFieldErrorPreferences = (name) => {
    if (formErrorsPreferences[name]) {
      setFormErrorsPreferences((prev) => {
        const next = { ...prev };
        delete next[name];
        if (Object.keys(next).length === 1 && next._form) {
          delete next._form;
        }
        return next;
      });
    }
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData({ ...formData, [name]: value });
    clearFieldError(name);
  };

  const handleInputChangePreferences = (e) => {
    const { name, value } = e.target;
    setFormData({ ...formData, [name]: value });
    clearFieldErrorPreferences(name);

    // If theme changed, update immediately
    if (name === 'theme') {
      updateTheme(value);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!isEditMode) { return; } // Only submit when in edit mode

    // Only validate address fields, not preferences
    const addressSchema = z.object({
      country: trimAndRequire(
        t('countryRequired', { ns: 'settings', defaultValue: 'Country is required' })
      ),
      city: trimAndRequire(
        t('cityRequired', { ns: 'settings', defaultValue: 'City is required' })
      ),
      area: trimAndRequire(
        t('areaRequired', { ns: 'settings', defaultValue: 'Area is required' })
      ),
      digital_address: trimAndRequire(
        t('digitalAddressRequired', {
          ns: 'settings',
          defaultValue: 'Digital address is required',
        })
      ).max(
        100,
        t('digitalAddressTooLong', {
          ns: 'settings',
          defaultValue: 'Digital address cannot exceed 100 characters',
        })
      ),
    });

    const validationInput = {
      country: formData.country || '',
      city: formData.city || '',
      area: formData.area || '',
      digital_address: formData.digital_address || '',
    };

    const validation = addressSchema.safeParse(validationInput);

    if (!validation.success) {
      const errors = mapFieldErrors(validation.error);
      setFormErrors(errors);
      const message = Object.values(errors)[0] || t('pleaseFillInAllFields', { ns: 'settings' });
      showError(message);
      return;
    }

    setFormErrors({});

    // Update address info
    const updateData = {
      country: formData.country,
      city: formData.city,
      area: formData.area,
      digitalAddress: formData.digital_address
    };

    // Execute mutation
    try {
      await updateProfileMutation.mutateAsync(updateData);

      success(t('profileUpdated', { ns: 'settings', defaultValue: 'Profile updated successfully!' }));

      // Refetch fresh data to ensure UI matches backend
      const freshProfileResp = await ProfileUtils.loadUserProfile();
      const remapped = ProfileUtils.mapProfileDataToForm(freshProfileResp);
      if (remapped) {
        const updatedData = { ...formData, ...remapped };
        setFormData(updatedData);
        setOriginalFormData(updatedData);
      }

      // Exit edit mode after successful save
      setFormErrors({});
      setIsEditMode(false);
    } catch (error) {
      if (!error?.message) {
        showError(t('failedToUpdateProfile', { ns: 'settings', defaultValue: 'Failed to update profile. Please try again.' }));
      }
    }
  };

  const handleSubmitPreferences = async (e) => {
    e.preventDefault();

    if (!isEditModePreferences) { return; } // Only submit when in edit mode

    // Only validate preference fields, not address fields
    const preferencesSchema = z.object({
      currency: trimAndRequire(
        t('currencyRequired', { ns: 'settings', defaultValue: 'Currency is required' })
      ),
      language: trimAndRequire(
        t('languageRequired', { ns: 'settings', defaultValue: 'Language is required' })
      ),
      notificationPreference: trimAndRequire(
        t('notificationPreferenceRequired', {
          ns: 'settings',
          defaultValue: 'Notification preference is required',
        })
      ),
      theme: trimAndRequire(
        t('themeRequired', { ns: 'settings', defaultValue: 'Theme is required' })
      ),
      timezone: trimAndRequire(
        t('timezoneRequired', { ns: 'settings', defaultValue: 'Timezone is required' })
      ),
    });

    const validationInput = {
      currency: formData.currency || '',
      language: formData.language || '',
      notificationPreference: formData.notificationPreference || '',
      theme: formData.theme || '',
      timezone: formData.timezone || '',
    };

    const validation = preferencesSchema.safeParse(validationInput);

    if (!validation.success) {
      const errors = mapFieldErrors(validation.error);
      setFormErrorsPreferences(errors);
      const message = Object.values(errors)[0] || t('pleaseFillInAllFields', { ns: 'settings' });
      showError(message);
      return;
    }

    setFormErrorsPreferences({});

    // Update preferences - include all preference fields
    const preferences = {
      currency: formData.currency,
      language: formData.language,
      notificationPreference: formData.notificationPreference,
      theme: formData.theme,
      timezone: formData.timezone,
    };

    // Execute mutation
    try {
      await updatePreferencesMutation.mutateAsync(preferences);

      // Apply theme immediately if it changed
      if (formData.theme) {
        updateTheme(formData.theme);
      }

      // Apply language change only after successful save
      if (formData.language && formData.language !== currentLanguage) {
        changeLanguage(formData.language);
      }

      // Refetch fresh data to ensure UI matches backend
      const freshPrefs = await ProfileUtils.loadPreferences();
      const savedLang = freshPrefs?.language || formData.language || currentLanguage;
      const updatedData = { 
        ...formData,
        currency: freshPrefs?.currency || formData.currency,
        language: savedLang,
        notificationPreference: freshPrefs?.notification_preference || freshPrefs?.notificationPreference || formData.notificationPreference,
        theme: formData.theme,
        timezone: formData.timezone,
      };
      setFormData(updatedData);
      setOriginalFormData(updatedData);
      
      // Update language context to match saved language
      if (savedLang !== currentLanguage) {
        changeLanguage(savedLang);
      }

      // Exit edit mode after successful save
      setFormErrorsPreferences({});
      setIsEditModePreferences(false);
    } catch (error) {
      if (!error?.message) {
        showError(t('failedToUpdatePreferences', { ns: 'settings', defaultValue: 'Failed to update preferences. Please try again.' }));
      }
    }
  };

  useEffect(() => {
    (async () => {
      const [profile, prefs] = await Promise.all([
        ProfileUtils.loadUserProfile(),
        ProfileUtils.loadPreferences(),
      ]);
      const mapped = ProfileUtils.mapProfileDataToForm(profile, prefs);
      if (mapped) {
        // Sync theme from ThemeContext (source of truth)
        const syncedMapped = {
          ...mapped,
          theme: theme || mapped.theme || 'Light',
        };
        setFormData((prev) => ({ ...prev, ...syncedMapped }));
        // Sync language if it's different from current (only on initial load)
        if (syncedMapped.language && syncedMapped.language !== currentLanguage) {
          changeLanguage(syncedMapped.language);
        }
      }
    })();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []); // Only run on mount, not when language changes

  // Sync theme in formData when ThemeContext theme changes
  useEffect(() => {
    if (theme && formData.theme !== theme) {
      setFormData((prev) => ({ ...prev, theme }));
    }
  }, [theme]);

  if (isFetchingProfile) {
    return (
      <div className="invoices-card">
        <div className="card-head">
          <h3>{t('personalInformation', { ns: 'settings' })}</h3>
          <p className="transaction-count">{t('loadingYourProfile', { ns: 'settings' })}</p>
        </div>
        <div className="form-card" style={{ textAlign: 'center' }}>
          <div style={{
            width: '32px',
            height: '32px',
            border: '3px solid #e5e7eb',
            borderTop: '3px solid #004895',
            borderRadius: '50%',
            animation: 'spin 1s linear infinite',
            margin: '0 auto 16px'
          }} />
          <p className="table-muted">{t('loadingProfileData', { ns: 'settings' })}</p>
        </div>
      </div>
    );
  }

  return (
    <>
      {/* Profile Information Card */}
      <form onSubmit={handleSubmit} style={{ marginBottom: '32px' }}>
      <div className="invoices-card">
        <div className="card-head" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '12px' }}>
          <div>
            <h3>{t('personalInformation', { ns: 'settings' })}</h3>
            <p className="transaction-count">{t('updatePersonalDetails', { ns: 'settings' })}</p>
          </div>
          {/* Edit Information Button in Header */}
          {!isEditMode && (
            <button
              type="button"
              onClick={handleEditClick}
              style={{
                padding: isMobile ? '8px 16px' : '10px 20px',
                backgroundColor: 'var(--accent)',
                color: 'var(--text-inverse)',
                border: 'none',
                borderRadius: '8px',
                cursor: 'pointer',
                fontSize: isMobile ? '13px' : '14px',
                fontWeight: '600',
                transition: 'all var(--transition-base)',
                display: 'flex',
                alignItems: 'center',
                gap: '6px'
              }}
              onMouseEnter={(e) => {
                e.target.style.backgroundColor = 'var(--accent-hover, #003d7a)';
                e.target.style.transform = 'translateY(-1px)';
              }}
              onMouseLeave={(e) => {
                e.target.style.backgroundColor = 'var(--accent)';
                e.target.style.transform = 'translateY(0)';
              }}
            >
              <span className="material-symbols-outlined" style={{ fontSize: 18 }}>edit</span>
              {t('editInformation', { ns: 'settings', defaultValue: 'Edit Information' })}
            </button>
          )}
        </div>

        <div className="form-card" style={{ padding: isMobile ? '16px' : '24px' }}>
          {/* Personal Information Section */}
          <div className="settings-section" data-tour="settings-profile-personal">
          <h4 className="card-section-head">
            <span className="material-symbols-outlined" style={{ fontSize: 20, color: 'var(--accent)' }}>person</span>
            {t('personalInformation', { ns: 'settings' })}
          </h4>

          {!isEditMode ? (
            // View Mode - Display as static data
            <div style={{ 
              display: 'grid', 
              gridTemplateColumns: isMobile ? '1fr' : isTablet ? 'repeat(2, 1fr)' : 'repeat(3, 1fr)', 
              gap: isMobile ? '16px' : '24px',
              padding: '16px 0'
            }}>
              <div style={{ 
                padding: '12px 16px', 
                backgroundColor: 'var(--bg-secondary)', 
                borderRadius: '8px',
                border: '1px solid var(--border-primary)'
              }}>
                <div style={{ fontSize: '12px', color: 'var(--text-muted)', marginBottom: '4px', fontWeight: '500' }}>
                  {t('firstName', { ns: 'settings' })}
                </div>
                <div style={{ fontSize: '15px', color: 'var(--text-primary)', fontWeight: '600' }}>
                  {formData.firstName || '-'}
                </div>
              </div>

              <div style={{ 
                padding: '12px 16px', 
                backgroundColor: 'var(--bg-secondary)', 
                borderRadius: '8px',
                border: '1px solid var(--border-primary)'
              }}>
                <div style={{ fontSize: '12px', color: 'var(--text-muted)', marginBottom: '4px', fontWeight: '500' }}>
                  {t('lastName', { ns: 'settings' })}
                </div>
                <div style={{ fontSize: '15px', color: 'var(--text-primary)', fontWeight: '600' }}>
                  {formData.lastName || '-'}
                </div>
              </div>

              <div style={{ 
                padding: '12px 16px', 
                backgroundColor: 'var(--bg-secondary)', 
                borderRadius: '8px',
                border: '1px solid var(--border-primary)'
              }}>
                <div style={{ fontSize: '12px', color: 'var(--text-muted)', marginBottom: '4px', fontWeight: '500' }}>
                  {t('phoneNumber', { ns: 'settings' })}
                </div>
                <div style={{ fontSize: '15px', color: 'var(--text-primary)', fontWeight: '600' }}>
                  {formData.phoneNumber || '-'}
                </div>
              </div>
            </div>
          ) : (
            // Edit Mode - Display as form inputs
            <div className="sms-form-row" style={{ gridTemplateColumns: isMobile ? '1fr' : isTablet ? 'repeat(2, 1fr)' : 'repeat(3, 1fr)', gap: isMobile ? '16px' : '20px' }}>
              <div className="sms-form-field">
                <label className="form-label">{t('firstName', { ns: 'settings' })}</label>
                <input
                  type="text"
                  name="firstName"
                  value={formData.firstName}
                  onChange={handleInputChange}
                  placeholder={t('enterFirstName', { ns: 'settings' })}
                  className="input-large"
                  required
                  readOnly
                  style={{ backgroundColor: 'var(--bg-tertiary)', cursor: 'not-allowed', color: 'var(--text-muted)' }}
                />
              </div>

              <div className="sms-form-field">
                <label className="form-label">{t('lastName', { ns: 'settings' })}</label>
                <input
                  type="text"
                  name="lastName"
                  value={formData.lastName}
                  onChange={handleInputChange}
                  placeholder={t('enterLastName', { ns: 'settings' })}
                  className="input-large"
                  required
                  readOnly
                  style={{ backgroundColor: 'var(--bg-tertiary)', cursor: 'not-allowed', color: 'var(--text-muted)' }}
                />
              </div>

              <div className="sms-form-field">
                <label className="form-label">{t('phoneNumber', { ns: 'settings' })}</label>
                <input
                  type="tel"
                  name="phoneNumber"
                  value={formData.phoneNumber}
                  onChange={handleInputChange}
                  placeholder={t('phoneNumberPlaceholder', { ns: 'settings', defaultValue: 'e.g. 233501234567' })}
                  className="input-large"
                  required
                  readOnly
                  style={{ backgroundColor: 'var(--bg-tertiary)', cursor: 'not-allowed', color: 'var(--text-muted)' }}
                />
              </div>
            </div>
          )}

        </div>

        {/* Address Information Section */}
        <div className="settings-section" data-tour="settings-profile-address">
          <h4 className="card-section-head">
            <span className="material-symbols-outlined" style={{ fontSize: 20, color: 'var(--accent)' }}>location_on</span>
            {t('addressInformation', { ns: 'settings' })}
          </h4>

          {!isEditMode ? (
            // View Mode - Display as static data
            <div style={{ 
              display: 'grid', 
              gridTemplateColumns: isMobile ? '1fr' : isTablet ? 'repeat(2, 1fr)' : 'repeat(2, 1fr)', 
              gap: isMobile ? '16px' : '24px',
              padding: '16px 0'
            }}>
              <div style={{ 
                padding: '12px 16px', 
                backgroundColor: 'var(--bg-secondary)', 
                borderRadius: '8px',
                border: '1px solid var(--border-primary)'
              }}>
                <div style={{ fontSize: '12px', color: 'var(--text-muted)', marginBottom: '4px', fontWeight: '500' }}>
                  {t('country', { ns: 'settings' })}
                </div>
                <div style={{ fontSize: '15px', color: 'var(--text-primary)', fontWeight: '600' }}>
                  {formData.country || '-'}
                </div>
              </div>

              <div style={{ 
                padding: '12px 16px', 
                backgroundColor: 'var(--bg-secondary)', 
                borderRadius: '8px',
                border: '1px solid var(--border-primary)'
              }}>
                <div style={{ fontSize: '12px', color: 'var(--text-muted)', marginBottom: '4px', fontWeight: '500' }}>
                  {t('city', { ns: 'settings' })}
                </div>
                <div style={{ fontSize: '15px', color: 'var(--text-primary)', fontWeight: '600' }}>
                  {formData.city || '-'}
                </div>
              </div>

              <div style={{ 
                padding: '12px 16px', 
                backgroundColor: 'var(--bg-secondary)', 
                borderRadius: '8px',
                border: '1px solid var(--border-primary)'
              }}>
                <div style={{ fontSize: '12px', color: 'var(--text-muted)', marginBottom: '4px', fontWeight: '500' }}>
                  {t('region', { ns: 'settings', defaultValue: 'Region' })}
                </div>
                <div style={{ fontSize: '15px', color: 'var(--text-primary)', fontWeight: '600' }}>
                  {formData.area || '-'}
                </div>
              </div>

              <div style={{ 
                padding: '12px 16px', 
                backgroundColor: 'var(--bg-secondary)', 
                borderRadius: '8px',
                border: '1px solid var(--border-primary)'
              }}>
                <div style={{ fontSize: '12px', color: 'var(--text-muted)', marginBottom: '4px', fontWeight: '500' }}>
                  {t('digitalAddress', { ns: 'settings' })}
                </div>
                <div style={{ fontSize: '15px', color: 'var(--text-primary)', fontWeight: '600' }}>
                  {formData.digital_address || '-'}
                </div>
              </div>
            </div>
          ) : (
            // Edit Mode - Display as form inputs
            <div className="sms-form-row" style={{ gridTemplateColumns: isMobile ? '1fr' : isTablet ? 'repeat(2, 1fr)' : 'repeat(2, 1fr)', gap: isMobile ? '16px' : '20px' }}>
              <div className="sms-form-field">
                <label className="form-label">{t('country', { ns: 'settings' })}</label>
                <CustomSelect
                  name="country"
                  value={formData.country}
                  onChange={handleInputChange}
                  options={countries.map(c => ({ value: c.name, label: c.name }))}
                  placeholder={t('selectCountry', { ns: 'settings' })}
                  disabled={!isEditMode}
                  error={formErrors.country}
                />
              </div>

              <div className="sms-form-field">
                <label className="form-label">{t('city', { ns: 'settings' })}</label>
                <input
                  type="text"
                  name="city"
                  value={formData.city}
                  onChange={handleInputChange}
                  placeholder={t('enterCity', { ns: 'settings' })}
                  className="input-large"
                  required
                  disabled={!isEditMode}
                  style={{
                    backgroundColor: isEditMode ? 'var(--bg-input)' : 'var(--bg-tertiary)',
                    cursor: isEditMode ? 'text' : 'not-allowed',
                    color: isEditMode ? 'var(--text-primary)' : 'var(--text-muted)'
                  }}
                />
                {formErrors.city && (
                  <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '4px' }}>
                    {formErrors.city}
                  </p>
                )}
              </div>

              <div className="sms-form-field">
                <label className="form-label">{t('region', { ns: 'settings', defaultValue: 'Region' })}</label>
                <CustomSelect
                  name="area"
                  value={formData.area}
                  onChange={handleInputChange}
                  options={ghanaRegions.map(r => ({ value: r, label: r }))}
                  placeholder={t('selectRegion', { ns: 'settings', defaultValue: 'Select region' })}
                  disabled={!isEditMode}
                  error={formErrors.area}
                />
              </div>

              <div className="sms-form-field">
                <label className="form-label">{t('digitalAddress', { ns: 'settings' })}</label>
                <input
                  type="text"
                  name="digital_address"
                  value={formData.digital_address}
                  onChange={handleInputChange}
                  placeholder={t('digitalAddressPlaceholder', { ns: 'settings', defaultValue: 'e.g., GCC-344-3454' })}
                  className="input-large"
                  required
                  disabled={!isEditMode}
                  style={{
                    backgroundColor: isEditMode ? 'var(--bg-input)' : 'var(--bg-tertiary)',
                    cursor: isEditMode ? 'text' : 'not-allowed',
                    color: isEditMode ? 'var(--text-primary)' : 'var(--text-muted)'
                  }}
                />
                {formErrors.digital_address && (
                  <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '4px' }}>
                    {formErrors.digital_address}
                  </p>
                )}
              </div>
            </div>
          )}
        </div>
      </div>

        {/* Action Buttons for Profile Information */}
        {isEditMode && (
          <div style={{ display: 'flex', gap: '12px', justifyContent: isMobile ? 'stretch' : 'flex-end', flexDirection: isMobile ? 'column-reverse' : 'row', marginTop: '16px' }}>
            <button
              type="button"
              onClick={handleCancelClick}
              disabled={updateProfileMutation.isPending}
              style={{
                padding: isMobile ? '10px 20px' : '12px 24px',
                backgroundColor: 'var(--bg-tertiary)',
                color: 'var(--text-primary)',
                border: '1px solid var(--border-primary)',
                borderRadius: '8px',
                cursor: updateProfileMutation.isPending ? 'not-allowed' : 'pointer',
                fontSize: isMobile ? '14px' : '16px',
                fontWeight: '600',
                opacity: updateProfileMutation.isPending ? 0.6 : 1,
                transition: 'all var(--transition-base)',
                width: isMobile ? '100%' : 'auto'
              }}
              onMouseEnter={(e) => {
                if (!updateProfileMutation.isPending) {
                  e.target.style.backgroundColor = 'var(--bg-hover)';
                }
              }}
              onMouseLeave={(e) => {
                e.target.style.backgroundColor = 'var(--bg-tertiary)';
              }}
            >
              {t('cancel', { ns: 'settings' })}
            </button>
            <button
              type="submit"
              disabled={updateProfileMutation.isPending}
              style={{
                display: 'inline-flex',
                alignItems: 'center',
                justifyContent: 'center',
                gap: '8px',
                padding: isMobile ? '10px 20px' : '12px 24px',
                backgroundColor: 'var(--accent)',
                color: 'var(--text-inverse)',
                border: 'none',
                borderRadius: '8px',
                cursor: updateProfileMutation.isPending ? 'not-allowed' : 'pointer',
                fontSize: isMobile ? '14px' : '16px',
                fontWeight: '600',
                opacity: updateProfileMutation.isPending ? 0.6 : 1,
                transition: 'all var(--transition-base)',
                width: isMobile ? '100%' : 'auto'
              }}
              onMouseEnter={(e) => {
                if (!updateProfileMutation.isPending) {
                  e.target.style.backgroundColor = 'var(--accent-hover, #003d7a)';
                  e.target.style.transform = 'translateY(-1px)';
                }
              }}
              onMouseLeave={(e) => {
                e.target.style.backgroundColor = 'var(--accent)';
                e.target.style.transform = 'translateY(0)';
              }}
            >
              {updateProfileMutation.isPending && (
                <div style={{
                  width: '16px',
                  height: '16px',
                  border: '2px solid transparent',
                  borderTop: '2px solid currentColor',
                  borderRadius: '50%',
                  animation: 'spin 1s linear infinite'
                }} />
              )}
              {updateProfileMutation.isPending ? t('saving', { ns: 'settings', defaultValue: 'Saving...' }) : t('saveChanges', { ns: 'settings', defaultValue: 'Save Changes' })}
            </button>
          </div>
        )}
      </div>
      </form>

      {/* User Preferences Card */}
      <form onSubmit={handleSubmitPreferences}>
      <div className="invoices-card" style={{ marginTop: '32px' }}>
        <div className="card-head" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '12px' }}>
          <div>
            <h3>{t('userPreferences', { ns: 'settings' })}</h3>
            <p className="transaction-count">{t('customizeYourExperience', { ns: 'settings', defaultValue: 'Customize your experience' })}</p>
          </div>
          {/* Edit Preferences Button in Header */}
          {!isEditModePreferences && (
            <button
              type="button"
              onClick={handleEditClickPreferences}
              style={{
                padding: isMobile ? '8px 16px' : '10px 20px',
                backgroundColor: 'var(--accent)',
                color: 'var(--text-inverse)',
                border: 'none',
                borderRadius: '8px',
                cursor: 'pointer',
                fontSize: isMobile ? '13px' : '14px',
                fontWeight: '600',
                transition: 'all var(--transition-base)',
                display: 'flex',
                alignItems: 'center',
                gap: '6px'
              }}
              onMouseEnter={(e) => {
                e.target.style.backgroundColor = 'var(--accent-hover, #003d7a)';
                e.target.style.transform = 'translateY(-1px)';
              }}
              onMouseLeave={(e) => {
                e.target.style.backgroundColor = 'var(--accent)';
                e.target.style.transform = 'translateY(0)';
              }}
            >
              <span className="material-symbols-outlined" style={{ fontSize: 18 }}>edit</span>
              {t('editPreferences', { ns: 'settings', defaultValue: 'Edit Preferences' })}
            </button>
          )}
        </div>

        <div className="form-card" style={{ padding: isMobile ? '16px' : '24px' }}>

          {/* User Preferences Section */}
          <div className="settings-section" data-tour="settings-profile-preferences">
          <h4 className="card-section-head">
            <span className="material-symbols-outlined" style={{ fontSize: 20, color: 'var(--accent)' }}>settings</span>
            {t('userPreferences', { ns: 'settings' })}
          </h4>

          {!isEditModePreferences ? (
            // View Mode - Display as static data
            <div style={{ 
              display: 'grid', 
              gridTemplateColumns: isMobile ? '1fr' : isTablet ? 'repeat(2, 1fr)' : 'repeat(2, 1fr)', 
              gap: isMobile ? '16px' : '24px',
              padding: '16px 0'
            }}>
              <div style={{ 
                padding: '12px 16px', 
                backgroundColor: 'var(--bg-secondary)', 
                borderRadius: '8px',
                border: '1px solid var(--border-primary)'
              }}>
                <div style={{ fontSize: '12px', color: 'var(--text-muted)', marginBottom: '4px', fontWeight: '500' }}>
                  {t('currency', { ns: 'settings' })}
                </div>
                <div style={{ fontSize: '15px', color: 'var(--text-primary)', fontWeight: '600' }}>
                  {formData.currency === 'GHS' ? t('ghanaianCedi', { ns: 'settings', defaultValue: 'Ghanaian Cedi (GHS)' }) :
                   formData.currency === 'USD' ? t('usDollar', { ns: 'settings', defaultValue: 'US Dollar (USD)' }) :
                   formData.currency === 'EUR' ? t('euro', { ns: 'settings', defaultValue: 'Euro (EUR)' }) :
                   formData.currency === 'GBP' ? t('britishPound', { ns: 'settings', defaultValue: 'British Pound (GBP)' }) :
                   formData.currency || '-'}
                </div>
              </div>

              <div style={{ 
                padding: '12px 16px', 
                backgroundColor: 'var(--bg-secondary)', 
                borderRadius: '8px',
                border: '1px solid var(--border-primary)'
              }}>
                <div style={{ fontSize: '12px', color: 'var(--text-muted)', marginBottom: '4px', fontWeight: '500' }}>
                  {t('language', { ns: 'settings' })}
                </div>
                <div style={{ fontSize: '15px', color: 'var(--text-primary)', fontWeight: '600' }}>
                  {formData.language === 'en' ? t('english', { ns: 'settings', defaultValue: 'English' }) :
                   formData.language === 'fr' ? t('french', { ns: 'settings', defaultValue: 'Français (French)' }) :
                   formData.language === 'ar' ? t('arabic', { ns: 'settings', defaultValue: 'العربية (Arabic)' }) :
                   formData.language === 'ha' ? t('hausa', { ns: 'settings', defaultValue: 'Hausa' }) :
                   formData.language || currentLanguage || '-'}
                </div>
              </div>

              <div style={{ 
                padding: '12px 16px', 
                backgroundColor: 'var(--bg-secondary)', 
                borderRadius: '8px',
                border: '1px solid var(--border-primary)'
              }}>
                <div style={{ fontSize: '12px', color: 'var(--text-muted)', marginBottom: '4px', fontWeight: '500' }}>
                  {t('notificationPreference', { ns: 'settings' })}
                </div>
                <div style={{ fontSize: '15px', color: 'var(--text-primary)', fontWeight: '600', textTransform: 'capitalize' }}>
                  {formData.notificationPreference || '-'}
                </div>
              </div>

              <div style={{ 
                padding: '12px 16px', 
                backgroundColor: 'var(--bg-secondary)', 
                borderRadius: '8px',
                border: '1px solid var(--border-primary)'
              }}>
                <div style={{ fontSize: '12px', color: 'var(--text-muted)', marginBottom: '4px', fontWeight: '500' }}>
                  {t('theme', { ns: 'settings' })}
                </div>
                <div style={{ fontSize: '15px', color: 'var(--text-primary)', fontWeight: '600' }}>
                  {formData.theme === 'Light' ? t('light', { ns: 'settings', defaultValue: 'Light' }) :
                   formData.theme === 'Dark' ? t('dark', { ns: 'settings', defaultValue: 'Dark' }) :
                   formData.theme === 'Auto' ? t('auto', { ns: 'settings', defaultValue: 'Auto (System)' }) :
                   formData.theme || '-'}
                </div>
              </div>

              <div style={{ 
                padding: '12px 16px', 
                backgroundColor: 'var(--bg-secondary)', 
                borderRadius: '8px',
                border: '1px solid var(--border-primary)',
                gridColumn: isMobile ? 'auto' : 'span 2'
              }}>
                <div style={{ fontSize: '12px', color: 'var(--text-muted)', marginBottom: '4px', fontWeight: '500' }}>
                  {t('timezone', { ns: 'settings' })}
                </div>
                <div style={{ fontSize: '15px', color: 'var(--text-primary)', fontWeight: '600' }}>
                  {formData.timezone === 'Africa/Accra' ? t('timezoneAccra', { ns: 'settings', defaultValue: 'Africa/Accra (GMT)' }) :
                   formData.timezone === 'America/New_York' ? t('timezoneNewYork', { ns: 'settings', defaultValue: 'America/New_York (EST)' }) :
                   formData.timezone === 'Europe/London' ? t('timezoneLondon', { ns: 'settings', defaultValue: 'Europe/London (GMT)' }) :
                   formData.timezone === 'Asia/Tokyo' ? t('timezoneTokyo', { ns: 'settings', defaultValue: 'Asia/Tokyo (JST)' }) :
                   formData.timezone || '-'}
                </div>
              </div>
            </div>
          ) : (
            // Edit Mode - Display as form inputs
            <div className="sms-form-row" style={{ gridTemplateColumns: isMobile ? '1fr' : isTablet ? 'repeat(2, 1fr)' : 'repeat(2, 1fr)', gap: isMobile ? '16px' : '20px' }}>
              <div className="sms-form-field">
                <label className="form-label">{t('currency', { ns: 'settings' })}</label>
                <CustomSelect
                  name="currency"
                  value={formData.currency}
                  onChange={handleInputChangePreferences}
                  options={[
                    { value: 'GHS', label: t('ghanaianCedi', { ns: 'settings', defaultValue: 'Ghanaian Cedi (GHS)' }) },
                    { value: 'USD', label: t('usDollar', { ns: 'settings', defaultValue: 'US Dollar (USD)' }) },
                    { value: 'EUR', label: t('euro', { ns: 'settings', defaultValue: 'Euro (EUR)' }) },
                    { value: 'GBP', label: t('britishPound', { ns: 'settings', defaultValue: 'British Pound (GBP)' }) }
                  ]}
                  disabled={!isEditModePreferences}
                  error={formErrorsPreferences.currency}
                />
              </div>

              <div className="sms-form-field">
                <label className="form-label">{t('language', { ns: 'settings' })}</label>
                <CustomSelect
                  name="language"
                  value={formData.language || currentLanguage}
                  onChange={handleInputChangePreferences}
                  options={[
                    { value: 'en', label: t('english', { ns: 'settings', defaultValue: 'English' }) },
                    { value: 'fr', label: t('french', { ns: 'settings', defaultValue: 'Français (French)' }) },
                    { value: 'ar', label: t('arabic', { ns: 'settings', defaultValue: 'العربية (Arabic)' }) },
                    { value: 'ha', label: t('hausa', { ns: 'settings', defaultValue: 'Hausa' }) }
                  ]}
                  disabled={!isEditModePreferences}
                  error={formErrorsPreferences.language}
                />
              </div>

              <div className="sms-form-field">
                <label className="form-label">{t('notificationPreference', { ns: 'settings' })}</label>
                <CustomSelect
                  name="notificationPreference"
                  value={formData.notificationPreference}
                  onChange={handleInputChangePreferences}
                  options={[
                    { value: 'email', label: t('email', { ns: 'settings' }) },
                    { value: 'sms', label: t('sms', { ns: 'settings' }) }
                  ]}
                  disabled={!isEditModePreferences}
                  error={formErrorsPreferences.notificationPreference}
                />
              </div>

              <div className="sms-form-field">
                <label className="form-label">{t('theme', { ns: 'settings' })}</label>
                <CustomSelect
                  name="theme"
                  value={formData.theme}
                  onChange={handleInputChangePreferences}
                  options={[
                    { value: 'Light', label: t('light', { ns: 'settings', defaultValue: 'Light' }) },
                    { value: 'Dark', label: t('dark', { ns: 'settings', defaultValue: 'Dark' }) },
                    { value: 'Auto', label: t('auto', { ns: 'settings', defaultValue: 'Auto (System)' }) }
                  ]}
                  disabled={!isEditModePreferences}
                  error={formErrorsPreferences.theme}
                />
              </div>

              <div className="sms-form-field">
                <label className="form-label">{t('timezone', { ns: 'settings' })}</label>
                <CustomSelect
                  name="timezone"
                  value={formData.timezone}
                  onChange={handleInputChangePreferences}
                  options={[
                    { value: 'Africa/Accra', label: t('timezoneAccra', { ns: 'settings', defaultValue: 'Africa/Accra (GMT)' }) },
                    { value: 'America/New_York', label: t('timezoneNewYork', { ns: 'settings', defaultValue: 'America/New_York (EST)' }) },
                    { value: 'Europe/London', label: t('timezoneLondon', { ns: 'settings', defaultValue: 'Europe/London (GMT)' }) },
                    { value: 'Asia/Tokyo', label: t('timezoneTokyo', { ns: 'settings', defaultValue: 'Asia/Tokyo (JST)' }) }
                  ]}
                  disabled={!isEditModePreferences}
                  error={formErrorsPreferences.timezone}
                />
              </div>
            </div>
          )}
        </div>
        </div>
      </div>

      {/* Action Buttons */}
      {isEditModePreferences && (
        <div className="full-width" style={{ display: 'flex', gap: '12px', justifyContent: isMobile ? 'stretch' : 'flex-end', flexDirection: isMobile ? 'column-reverse' : 'row', marginTop: '16px' }}>
          <button
            type="button"
            onClick={handleCancelClickPreferences}
            disabled={updatePreferencesMutation.isPending}
            style={{
              padding: isMobile ? '10px 20px' : '12px 24px',
              backgroundColor: 'var(--text-muted)',
              color: 'var(--text-inverse)',
              border: 'none',
              borderRadius: '8px',
              cursor: updatePreferencesMutation.isPending ? 'not-allowed' : 'pointer',
              fontSize: isMobile ? '14px' : '16px',
              fontWeight: '600',
              opacity: updatePreferencesMutation.isPending ? 0.6 : 1,
              transition: 'all var(--transition-base)',
              width: isMobile ? '100%' : 'auto'
            }}
          >
            {t('cancel', { ns: 'settings' })}
          </button>
          <button
            type="submit"
            disabled={updatePreferencesMutation.isPending}
            className="btn primary sms-submit"
            style={{
              display: 'inline-flex',
              alignItems: 'center',
              justifyContent: 'center',
              gap: '8px',
              padding: isMobile ? '10px 20px' : '12px 24px',
              fontSize: isMobile ? '14px' : '16px',
              width: isMobile ? '100%' : 'auto'
            }}
          >
            {updatePreferencesMutation.isPending && (
              <div style={{
                width: '16px',
                height: '16px',
                border: '2px solid transparent',
                borderTop: '2px solid currentColor',
                borderRadius: '50%',
                animation: 'spin 1s linear infinite'
              }} />
            )}
            {updatePreferencesMutation.isPending ? t('updating', { ns: 'settings' }) : t('saveChanges', { ns: 'settings', defaultValue: 'Save Changes' })}
          </button>
        </div>
      )}
    </form>
    </>
  );
};

export default Profile;
